/**
 * init-db.js — Création et peuplement de la base SQLite
 * Projet : Suivi Réservations
 *
 * Usage :
 *   node init-db.js           → crée la base si elle n'existe pas
 *   node init-db.js --reset   → supprime et recrée complètement
 *
 * Tables créées :
 *   owners       — propriétaires
 *   listings     — appartements (liés aux owners)
 *   reservations — réservations (liées aux listings)
 *
 * Colonnes réservations :
 *   duree      = durée du séjour en jours
 *   prix_nuit  = prix par nuit (€)
 *   prix_total = prix total du séjour (€)
 */

'use strict';
const Database = require('better-sqlite3');
const path     = require('path');
const fs       = require('fs');

const DB_PATH = path.join(__dirname, 'reservations.db');

if (process.argv.includes('--reset')) {
  if (fs.existsSync(DB_PATH)) {
    fs.unlinkSync(DB_PATH);
    console.log('Base existante supprimée (--reset).');
  }
}

const db = new Database(DB_PATH);
db.pragma('journal_mode = WAL');
db.pragma('foreign_keys = ON');

/* ── Création des tables ─────────────────────────────────────────────────── */
db.exec(`

  CREATE TABLE IF NOT EXISTS owners (
    id   TEXT PRIMARY KEY,
    nom  TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS listings (
    id           TEXT PRIMARY KEY,
    nom          TEXT NOT NULL,
    owner_id     TEXT,
    titre        TEXT,
    comm         REAL,
    active       INTEGER NOT NULL DEFAULT 1,
    menage       REAL,
    revenue_net  TEXT,
    commission_f TEXT,
    versement_f  TEXT,
    external_url TEXT,
    type         TEXT,
    FOREIGN KEY (owner_id) REFERENCES owners(id)
  );

  CREATE TABLE IF NOT EXISTS reservations (
    id           TEXT PRIMARY KEY,
    listing_id   TEXT NOT NULL,
    plateforme   TEXT,
    date_debut   TEXT,
    duree        INTEGER,
    prix_nuit    REAL,
    prix_total   REAL,
    menage       REAL,
    commission   REAL,
    hobe         REAL,
    versement    REAL,
    booking_date TEXT,
    FOREIGN KEY (listing_id) REFERENCES listings(id)
  );

  CREATE INDEX IF NOT EXISTS idx_listings_owner  ON listings(owner_id);
  CREATE INDEX IF NOT EXISTS idx_res_listing     ON reservations(listing_id);
  CREATE INDEX IF NOT EXISTS idx_res_plateforme  ON reservations(plateforme);
  CREATE INDEX IF NOT EXISTS idx_res_date_debut  ON reservations(date_debut);
  CREATE INDEX IF NOT EXISTS idx_res_booking     ON reservations(booking_date);

`);
console.log('Tables créées.');

/* ── Insertion de toutes les données dans une transaction ────────────────── */
